  ('retired-10ced7e2-moex-00283', 'retired-10ced7e2', 'retired-10ced7e2-moex-110-3d2b73b6', 'sub-retired-10ced7e2-03', NULL, 'single_choice', '下列何者屬於司法院大法官違憲審查之客體？', '["學校對於學生之退學處分", "限制人民從事特定職業之法律", "總統之統治行為", "法院之判決"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:19+00:00", "source_pdf_sha1": "a9bdc9366918", "answer_pdf_sha1": "6fe561860812", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "135", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "人事行政"}'::jsonb, NULL),
  ('retired-10ced7e2-moex-00284', 'retired-10ced7e2', 'retired-10ced7e2-moex-110-3d2b73b6', 'sub-retired-10ced7e2-03', NULL, 'single_choice', '依立法院職權行使法之規定，關於行政命令之審查，下列敘述何者錯誤？', '["各機關依其法定職權或基於法律授權訂定之命令送達立法院後，應提報立法院會議", "各委員會審查行政命令，原則上應於院會交付審查後6個月內完成之；逾期未完成者，視為已經審查", "行政命令經審查後，發現有牴觸法律者，應提報院會，經議決後，通知原訂頒之機關更正或廢止之", "經通知原訂頒機關更正或廢止之命令，原訂頒機關應於2個月內更正或廢止；逾期未為更正或廢止者， 該命令失效"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:19+00:00", "source_pdf_sha1": "a9bdc9366918", "answer_pdf_sha1": "6fe561860812", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "135", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "人事行政"}'::jsonb, NULL),
  ('retired-10ced7e2-moex-00285', 'retired-10ced7e2', 'retired-10ced7e2-moex-110-3d2b73b6', 'sub-retired-10ced7e2-03', NULL, 'single_choice', '有關地方自治團體權限，下列敘述何者正確？', '["得訂定自治規則，規範所營事業機構之組織", "得銓定所任用公務人員之資格", "得依地方稅法通則之規定，以地方自治條例徵收地方稅", "對於負有協力義務之事項，得拒絕分擔經費"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:19+00:00", "source_pdf_sha1": "a9bdc9366918", "answer_pdf_sha1": "6fe561860812", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "135", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "人事行政"}'::jsonb, NULL),
  ('retired-10ced7e2-moex-00286', 'retired-10ced7e2', 'retired-10ced7e2-moex-110-3d2b73b6', 'sub-retired-10ced7e2-03', NULL, 'single_choice', '依地方制度法規定，直轄市議員、直轄市長有下列何種事由時，行政院得解除其職權？', '["犯內亂、外患或貪污罪，經判刑確定者", "被票據交換所列為拒絕往來戶者", "患有重大難治之疾病，連續2月無法上班者", "因欠稅導致其財產遭行政執行分署查封者"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:19+00:00", "source_pdf_sha1": "a9bdc9366918", "answer_pdf_sha1": "6fe561860812", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "135", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "人事行政"}'::jsonb, NULL),
  ('retired-10ced7e2-moex-00287', 'retired-10ced7e2', 'retired-10ced7e2-moex-110-3d2b73b6', 'sub-retired-10ced7e2-03', NULL, 'single_choice', '直轄市議員除現行犯、通緝犯外，在下列何項期間內，非經直轄市議會之同意，不得逮捕或拘禁？', '["任期內", "會期內", "休會期間", "會議進行中"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:19+00:00", "source_pdf_sha1": "a9bdc9366918", "answer_pdf_sha1": "6fe561860812", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "135", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "人事行政"}'::jsonb, NULL),
  ('retired-10ced7e2-moex-00288', 'retired-10ced7e2', 'retired-10ced7e2-moex-110-3d2b73b6', 'sub-retired-10ced7e2-03', NULL, 'single_choice', '關於憲法第23條法律保留原則，下列敘述何者正確？', '["基於權力分立原則，立法權應於法律中保留一定之判斷餘地給行政權", "國家對人民生命、身體自由或其他重要自由權利之限制，應由國會通過法律加以規定", "國家達成該目的有多種手段時，必須選擇侵害最小者", "國家應使尋求法律救濟的人民得以保留原先更有利的法律地位"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:19+00:00", "source_pdf_sha1": "a9bdc9366918", "answer_pdf_sha1": "6fe561860812", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "135", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "人事行政"}'::jsonb, NULL),
  ('retired-10ced7e2-moex-00289', 'retired-10ced7e2', 'retired-10ced7e2-moex-110-3d2b73b6', 'sub-retired-10ced7e2-03', NULL, 'single_choice', '依司法院大法官解釋，下列何者不違反比例原則？', '["對於應迴避而不迴避之公職人員，未衡酌情節輕微情形，一律處以100萬元以上之罰鍰", "對於遮斷器已開始放下仍強行闖越平交道，並因而肇事之汽車駕駛人，吊銷其駕駛執照", "計程車駕駛人，在執業期間犯竊盜罪，經法院判決有期徒刑確定者，廢止其執業登記，並吊銷其駕駛執照", "臺灣地區人民已有子女者，不予認可收養其配偶之大陸地區子女"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:19+00:00", "source_pdf_sha1": "a9bdc9366918", "answer_pdf_sha1": "6fe561860812", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "135", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "人事行政"}'::jsonb, NULL),
  ('retired-10ced7e2-moex-00290', 'retired-10ced7e2', 'retired-10ced7e2-moex-110-3d2b73b6', 'sub-retired-10ced7e2-03', NULL, 'single_choice', '如行政院環境保護署擬代行地方政府處理事業廢棄物非法棄置場址之清理，下列敘述何者錯誤？', '["須地方自治團體依法應作為而不作為，致嚴重危害公益或妨礙政務正常運作", "原則上須行政院環境保護署先命地方自治團體於一定期限內作為而仍不作為", "代行處理所支出之費用，應由行政院環境保護署負擔", "地方自治團體認為行政院環境保護署代行處理之決定違法時，得提起行政救濟 2701"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:19+00:00", "source_pdf_sha1": "a9bdc9366918", "answer_pdf_sha1": "6fe561860812", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "135", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "人事行政"}'::jsonb, NULL),
  ('retired-10ced7e2-moex-00291', 'retired-10ced7e2', 'retired-10ced7e2-moex-110-3d2b73b6', 'sub-retired-10ced7e2-03', NULL, 'single_choice', '稱契約自由者，謂當事人得以契約形成私法法律關係。下列何者不是契約自由之內容？', '["締約自由", "撤銷自由", "內容自由", "當事人自由"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:19+00:00", "source_pdf_sha1": "a9bdc9366918", "answer_pdf_sha1": "6fe561860812", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "135", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "人事行政"}'::jsonb, NULL),
  ('retired-10ced7e2-moex-00292', 'retired-10ced7e2', 'retired-10ced7e2-moex-110-3d2b73b6', 'sub-retired-10ced7e2-03', NULL, 'single_choice', '甲有A屋一棟，委任乙管理之，但未授與乙代理權。乙本於該委任而僱用丙粉刷A屋工資新臺幣（以下 同）20萬元，其又以每月租金20萬元將A屋出租予丁。依民法規定，下列敘述何者錯誤？', '["若乙已支付工資20萬元予丙，乙得請求甲償還之，並付支出時起之利息", "若乙尚未支付工資予丙，乙不得請求甲代為清償", "乙得基於租賃契約，向丁按月請求給付租金", "甲就乙自丁所收取之租金，得請求乙交付之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:19+00:00", "source_pdf_sha1": "a9bdc9366918", "answer_pdf_sha1": "6fe561860812", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "135", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "人事行政"}'::jsonb, NULL)
